// ---------------------------------------------------------------------------
// bench.cu -- benchmarks conv2d_naive on each test case.
//
// Build:
//   nvcc -O2 -Iinclude bench.cu src/conv2d_naive.cu -o bench_conv2d
// Run:
//   ./bench_conv2d
//
// Requires testdata/ to have been generated by gen_testdata.py (for shapes).
// Uses random input -- doesn't check correctness, just measures speed.
// ---------------------------------------------------------------------------

#include "conv2d.cuh"

#include <cuda_runtime.h>
#include <algorithm>
#include <cstdio>
#include <cstdlib>
#include <fstream>
#include <string>
#include <vector>

#define CUDA_OK(call)                                                          \
    do {                                                                       \
        cudaError_t _e = (call);                                               \
        if (_e != cudaSuccess) {                                               \
            std::fprintf(stderr, "CUDA error: %s\n", cudaGetErrorString(_e));  \
            std::exit(1);                                                      \
        }                                                                      \
    } while (0)

static constexpr int WARMUP_RUNS = 5;
static constexpr int TIMED_RUNS  = 50;

static void bench_case(int case_idx) {
    char tag[16];
    std::snprintf(tag, sizeof(tag), "case%02d", case_idx);

    // --- read shape ---
    ConvParams p;
    int OH, OW;
    {
        std::string shape_path = std::string("testdata/") + tag + "_shape.txt";
        std::ifstream f(shape_path);
        if (!f) { std::fprintf(stderr, "missing %s\n", shape_path.c_str()); std::exit(1); }
        f >> p.N >> p.C_in >> p.C_out >> p.H >> p.W
          >> p.KH >> p.KW >> p.pad >> p.stride >> OH >> OW;
    }

    const size_t in_n  = (size_t)p.N * p.C_in  * p.H * p.W;
    const size_t w_n   = (size_t)p.C_out * p.C_in * p.KH * p.KW;
    const size_t out_n = (size_t)p.N * p.C_out * OH * OW;

    // Allocate device buffers. Contents don't matter for timing.
    float *d_in, *d_w, *d_out;
    CUDA_OK(cudaMalloc(&d_in,  in_n  * sizeof(float)));
    CUDA_OK(cudaMalloc(&d_w,   w_n   * sizeof(float)));
    CUDA_OK(cudaMalloc(&d_out, out_n * sizeof(float)));
    CUDA_OK(cudaMemset(d_in,  0, in_n  * sizeof(float)));
    CUDA_OK(cudaMemset(d_w,   0, w_n   * sizeof(float)));

    dim3 block(TILE_W, TILE_H, 1);
    dim3 grid((OW + TILE_W - 1) / TILE_W,
              (OH + TILE_H - 1) / TILE_H,
              p.N * p.C_out);

    // --- warmup (untimed) ---
    for (int i = 0; i < WARMUP_RUNS; ++i) {
        conv2d_naive<<<grid, block>>>(d_in, d_w, d_out, p);
    }
    CUDA_OK(cudaDeviceSynchronize());

    // --- timed runs ---
    cudaEvent_t start, stop;
    CUDA_OK(cudaEventCreate(&start));
    CUDA_OK(cudaEventCreate(&stop));

    std::vector<float> times_ms(TIMED_RUNS);
    for (int i = 0; i < TIMED_RUNS; ++i) {
        CUDA_OK(cudaEventRecord(start));
        conv2d_naive<<<grid, block>>>(d_in, d_w, d_out, p);
        CUDA_OK(cudaEventRecord(stop));
        CUDA_OK(cudaEventSynchronize(stop));
        CUDA_OK(cudaEventElapsedTime(&times_ms[i], start, stop));
    }

    cudaEventDestroy(start);
    cudaEventDestroy(stop);
    cudaFree(d_in); cudaFree(d_w); cudaFree(d_out);

    // --- summarize ---
    std::sort(times_ms.begin(), times_ms.end());
    float min_ms    = times_ms.front();
    float median_ms = times_ms[TIMED_RUNS / 2];
    float mean_ms   = 0.0f;
    for (float t : times_ms) mean_ms += t;
    mean_ms /= TIMED_RUNS;

    // FLOPs = 2 * N * C_out * OH * OW * C_in * KH * KW
    double flops = 2.0 * p.N * p.C_out * OH * OW
                       * p.C_in * p.KH * p.KW;
    double gflops_min    = (flops / 1e9) / (min_ms    / 1000.0);
    double gflops_median = (flops / 1e9) / (median_ms / 1000.0);

    std::printf(
        "[%s] N=%d Cin=%-2d Cout=%-3d H=%-3d W=%-3d K=%dx%d s=%d  "
        "min=%.3f ms  median=%.3f ms  mean=%.3f ms  "
        "peak=%.1f GFLOPS  median=%.1f GFLOPS\n",
        tag, p.N, p.C_in, p.C_out, p.H, p.W, p.KH, p.KW, p.stride,
        min_ms, median_ms, mean_ms, gflops_min, gflops_median);
}

int main() {
    const int NUM_CASES = 7;

    // Print GPU info once at the top.
    int dev;
    CUDA_OK(cudaGetDevice(&dev));
    cudaDeviceProp prop;
    CUDA_OK(cudaGetDeviceProperties(&prop, dev));
    int clock_khz = 0;
    cudaDeviceGetAttribute(&clock_khz, cudaDevAttrClockRate, dev);
    std::printf("GPU: %s  (SMs=%d, clock=%.2f GHz)\n\n",
                prop.name, prop.multiProcessorCount,
                clock_khz / 1e6);
    std::printf("Warmup=%d runs, Timed=%d runs per case\n\n",
                WARMUP_RUNS, TIMED_RUNS);

    for (int i = 0; i < NUM_CASES; ++i) bench_case(i);
    return 0;
}
